class Solution {
public:
    vector<int> pivotArray(vector<int>& nums, int pivot) {
        vector<int> less(nums.begin(), nums.end());
        vector<int> equal;
        vector<int> greater(nums.begin(), nums.end());

        for (int num : nums) {
            if (num < pivot) {
                less.pop_back();
                less.push_back(num);
            } else if (num == pivot) {
                equal.push_back(num);
            } else {
                greater.pop_back();
                greater.push_back(num);
            }
        }

        less.insert(less.end(), equal.begin(), equal.end());
        less.insert(less.end(), greater.begin(), greater.end());

        return less;
    }
};
